// GET /api/system/version — returns current version and latest available (onprem only)
import { NextResponse } from 'next/server'
import { requireAuth } from '@/lib/api'
import { execSync } from 'child_process'
import fs from 'fs'
import path from 'path'

export async function GET() {
  const { error } = await requireAuth(['TENANT_ADMIN'])
  if (error) return error

  if (process.env.NEXT_PUBLIC_MODE !== 'onprem') {
    return NextResponse.json({ error: 'Not available in SaaS mode' }, { status: 400 })
  }

  // Current version from package.json
  let current = 'unknown'
  try {
    const pkgPath = path.join(process.cwd(), 'package.json')
    const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf8'))
    current = pkg.version ?? 'unknown'
  } catch {}

  // Latest version — use git ls-remote with the server's existing SSH key.
  // This works for private repos without any API token.
  let latest = current
  let updateAvailable = false
  let latestError: string | null = null

  try {
    const APP_DIR = '/home/edudesk/edudesk'
    // Get remote url from git config (works for both SSH and HTTPS remotes)
    const remoteUrl = execSync('git remote get-url origin', { cwd: APP_DIR, timeout: 5000 })
      .toString().trim()

    // List all tags on the remote
    const raw = execSync(`git ls-remote --tags "${remoteUrl}"`, {
      cwd: APP_DIR,
      timeout: 10000,
      env: { ...process.env, GIT_SSH_COMMAND: 'ssh -o StrictHostKeyChecking=no' },
    }).toString()

    // Parse tag names, sort descending by semver, pick highest
    const tags = raw.split('\n')
      .map(l => l.split('\t')[1])
      .filter(r => r && r.startsWith('refs/tags/') && !r.endsWith('^{}'))
      .map(r => r.replace('refs/tags/', '').replace(/^v/, ''))
      .filter(Boolean)
      .sort((a, b) => {
        const pa = a.split('.').map(Number)
        const pb = b.split('.').map(Number)
        for (let i = 0; i < 3; i++) if ((pa[i]||0) !== (pb[i]||0)) return (pb[i]||0) - (pa[i]||0)
        return 0
      })

    if (tags.length > 0) {
      latest = tags[0]
      updateAvailable = latest !== current
    } else {
      latestError = 'No tags found on remote'
    }
  } catch (e: any) {
    latestError = e.message?.split('\n')[0] ?? 'git ls-remote failed'
  }

  return NextResponse.json({ current, latest, updateAvailable, latestError })
}
